import style from "./index.module.scss"

export default class Dropdown extends HTMLElement {
  set arrow(value: string) {
    this.setAttribute("arrow", value)
  }
  get arrow(): boolean {
    const value = this.getAttribute("arrow")
    return value === "true" || this.hasAttribute("arrow") ? true : false
  }
  static get observedAttributes() {
    return ['arrow'];
  }
  constructor() {
    super();
    const shadowRoot = this.attachShadow({ mode: 'open' });
    const sheet = new CSSStyleSheet();
    sheet.replaceSync(style);
    shadowRoot.adoptedStyleSheets = [sheet];
    shadowRoot.innerHTML = `
      <div part="root" id="dropdown">
        <div part="trigger" id="trigger" aria-labelledby="label" aria-control="popup">
          <span part="label" id="label">
            <slot name="trigger"></slot>
          </span>
          <span part="icon" id="icon">
            <huanlin-icon name="arrow-down"></huanlin-icon>
          </span>
        </div>
        <div part="popup" id="popup">
          <slot></slot>
        </div>
      </div>
    `
  }
  handleDropdownOpenClose = e => {
    // handle popup
    const popup = this.shadowRoot.querySelector("#popup")
    const active = popup.classList.contains("active")
    if (active) {
      popup.classList.remove("active")
    } else {
      popup.classList.add("active")
    }

    const item = e.target.closest("huanlin-menu-item")
    if (item) {
      this.setActiveItem(item.name)
      this.focusTrigger()
    }
  }
  willLoad = () => {
    this.popup = this.shadowRoot?.querySelector("#popup")
    this.shadowRoot.querySelector("#dropdown").addEventListener("click", this.handleDropdownOpenClose)
    this.shadowRoot.querySelector("#trigger").addEventListener("keydown", this.handleKeyboard)
    this.shadowRoot.querySelector("#popup").addEventListener("keydown", this.handleMenuArrow)
    this.addEventListener("keydown", this.handleCloseKeyboard)
    document.body.addEventListener("click", this.handleClickOutside)
  }
  connectedCallback() {
    this.classList.add("hydrated")
    this.willLoad()
    this.render()
  }
  render = () => {

  }
  disconnectedCallback() {
    document.body.removeEventListener("click", this.handleClickOutside)
    this.removeEventListener("keydown", this.handleCloseKeyboard)
    this.shadowRoot.querySelector("#popup").removeEventListener("keydown", this.handleMenuArrow)
    this.shadowRoot.querySelector("#dropdown").removeEventListener("click", this.handleDropdownOpenClose)
    this.shadowRoot.querySelector("#trigger").removeEventListener("keydown", this.handleKeyboard)
  }

  setActiveItem = (name) => {
    // set active item
    const itemList = Array.from(this.querySelectorAll("huanlin-menu-item"))
    itemList.forEach(item => {
      if (item.name === name) {
        item.setAttribute("active", "")
      } else {
        item.removeAttribute("active")
      }
    })
  }

  handleMenuArrow = e => {
    if (e.key === "ArrowDown") {
      const items = this.getItems()
      const index = items.indexOf(e.target)
      const current = index + 1
      if (current < 0 || current >= items.length) return
      items[current].setFocus()
    } else if (e.key === "ArrowUp") {
      const items = this.getItems()
      const index = items.indexOf(e.target)
      const current = index - 1
      if (current < 0 || current >= items.length) return
      items[current].setFocus()
    } else if (e.key === "Enter") {
      this.setActiveItem(e.target.name)
      this.hide()
      setTimeout(() => {
        this.focusTrigger()
      })
    }
  }

  getItems = () => {
    return Array.from(this.querySelectorAll("huanlin-menu-item"))
  }

  handleCloseKeyboard = e => {
    if (e.key === "Escape") {
      this.hide()
      this.focusTrigger()
    } else if (e.key === "Tab" || e.shiftKey && e.key === "Tab") {
      this.hide()
    }
  }

  focusTrigger = async () => {
    await this.querySelector("[slot='trigger']").setFocus()
  }

  handleKeyboard = e => {
    if (["ArrowDown", " ", "Enter"].includes(e.key)) {
      this.show()
      const items = this.getItems()
      items.length && items[0].setFocus()
    }
  }

  handleClickOutside = e => {
    if (!this.contains(e.target)) {
      this.hide()
    }
  }

  isOpen = () => {
    return this.popup.classList.contains("active")
  }

  show = () => {
    this.popup.classList.add("active")
  }

  hide = () => {
    this.popup.classList.remove("active")
  }
}
